get_external_identification_function:
// 1. Helpers e Constantes
const COMMERCIAL_USER_TYPES = ['commercial'];

const findValueByName = (fieldNames) => {
    const names = Array.isArray(fieldNames) ? fieldNames : [fieldNames];
    for (const interactionResponse of responses ?? []) {
        for (const name of names) {
            const value = interactionResponse?.responses?.[name];
            if (value) return value;
        }
    }
    return '';
};

const getCommercialDocument = () => {
    if (!COMMERCIAL_USER_TYPES.includes(userAccountRequested?.type)) return null;
    const doc = userAccountRequested?.social_number ? String(userAccountRequested.social_number).replace(/\D/g, '') : '';
    return doc ? [doc] : null;
};

// 2. Construção do Objeto de Resposta Base
const buildResponse = () => {
    const externalId = userAccountRequested.external_identification;

    // Cenário: Advisor
    if (userAccountRequested.type === 'advisor') {
        const advisorFormId = '5f6e995c-97e3-4bbd-97c2-8217a98155d7';
        const advisorData = responses?.find(resp => resp?.workflow_form_id === advisorFormId);
        const susep = advisorData?.responses?.susepDoCorretor;

        return susep 
            ? { advisor_susep: externalId, susep } 
            : { advisor_susep: externalId };
    }

    // Cenário: Sessão JWT Ativa
    if (accessSession?.jwt_token) {
        const { decryptTokenAES, decodeJWT, settings } = utils;
        const decryptedToken = decryptTokenAES(accessSession.jwt_token.replace(/ /g, '+'), settings.aes_encryption.encryption_key);
        const decodedJWT = decodeJWT(decryptedToken);

        if (decodedJWT?.userIdAssessor && decodedJWT?.flagAssessoria === 2) {
            return {
                susep: externalId,
                advisor_susep: decodedJWT?.userIdAssessor
            };
        }
    }

    // Cenário Padrão / Outros
    return {
        "id_ramo": findValueByName('id_ramo') || "",
        "ramo": findValueByName('ramo') || "",
        susep: externalId
    };
};

// 3. Execução e Injeção do Documento Comercial (se houver)
const finalResponse = buildResponse();
const commercialDoc = getCommercialDocument();

if (commercialDoc) {
    finalResponse.commercial_document = commercialDoc;
}

return finalResponse;

