return function onLoad() {
  const divs = {
    'Corretor Assessorado': [
      'susepDoCorretor'
    ]
  };

  let itemsActive = [];

  if (val in divs) {
    itemsActive = divs[val];
  }

  const nomeAssessorDiv = document.querySelector(`[data-test="form-field-nomeAssessor"]`);
  const documentoDoCorretorDiv = document.querySelector(`[data-test="form-field-documentoDoCorretor"]`);

  nomeAssessorDiv.style.display = 'none';
  documentoDoCorretorDiv.style.display = 'none';

  Object.keys(divs).forEach(key => {
    divs[key].forEach(field => {
      const ele = document.querySelector(`[data-test="form-field-${field}"]`);
      if (ele) {
        if (!itemsActive.includes(field)) {
          ele.style.display = 'none';
            formData[field] = '';
        } else {
          ele.style.display = 'block';
        }
      }
    });
  });
};

